import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create({
  chat: {
    OpenAIChatCompletion('gpt-4o', { apiKey: process.env.OPENAI_API_KEY })
  }
});

const planner = kernel.importServiceFromObject(
  SequentialPlanner(kernel),
  'planner'
);

// Native function for RAG
const ragFunction = kernel.createFunctionFromPrompt({
  prompt: 'Retrieve relevant docs for: {{$input}}',
  name: 'rag_retrieve',
  description: 'Multi-source retrieval'
});

async function executeAgent(kernel: Kernel, query: string) {
  const plan = await planner.createPlan({
    goal: `Answer: ${query} with citations`
  });

  const result = await plan.invokeAsync({});
  return result.toString();
}

