import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: 'vex_...' });

// Vex plan validation middleware
kernel.registerExecutionHook(async (context, next) => {
  const plan = context.plan;

  const verdict = await vex.verify({
    suiteId: 'agentic-rag-planner',
    input: plan.goal,
    output: JSON.stringify(plan.steps),
    checkTypes: ['query_planning_accuracy', 'execution_order']
  });

  if (!verdict.passed) {
    throw new Error(`Invalid plan: ${verdict.reason}`);
  }

  return next();
});
